    if order.get('status') != 'active':
        continue
    med_concept = order.get('medicationCodeableConcept', {})
    found = False
    # Check display, code, and text fields for any keyword
    for coding in med_concept.get('coding', []):
        for keyword in indication_keywords:
            if (
                (coding.get('display') and keyword.lower() in coding['display'].lower()) or
                (coding.get('code') and keyword.lower() in coding['code'].lower())
            ):
                found = True
                break
        if found:
            break
    if not found and med_concept.get('text'):
        for keyword in indication_keywords:
            if keyword.lower() in med_concept['text'].lower():
                found = True
                break
    if found:
        active_orders.append(order)

