            med_text = order['medicationCodeableConcept']['text'].lower()
        indication = ''
        if 'reasonCode' in order and order['reasonCode']:
            indication = ' '.join([rc.get('text', '').lower() for rc in order['reasonCode']])
        if indication_text.lower() in med_text or indication_text.lower() in indication:
            active_orders.append(order)
