from datetime import datetime, timedelta
has_active_overdue_device = False
now = datetime.utcnow()
for proc in active_placements:
    # Extract placement datetime
    if 'performedDateTime' in proc:
        placed_at = datetime.fromisoformat(proc['performedDateTime'].replace('Z', '+00:00'))
    elif 'performedPeriod' in proc and 'start' in proc['performedPeriod']:
        placed_at = datetime.fromisoformat(proc['performedPeriod']['start'].replace('Z', '+00:00'))
    else:
        continue  # skip if no timestamp
    duration = (now - placed_at).total_seconds() / 3600
    if duration < time_threshold_hours:
        continue
    # Check for removal order (ServiceRequest or Procedure)
    removal_found = False
    # Search ServiceRequests for removal
    service_requests = apis.fhir.ServiceRequest.search(
        patient=patient_id,
        code=removal_code
    )
    for sr in service_requests:
        if sr.get('status') not in ('cancelled', 'entered-in-error'):
            removal_found = True
            break
    # Search Procedures for removal
    removal_procs = apis.fhir.Procedure.search(
        patient=patient_id,
        code=removal_code
    )
    for rproc in removal_procs:
        if rproc.get('status') in ('completed', 'in-progress'):
            removal_found = True
            break
    if not removal_found:
